        let handles: Vec<_> = (0..10).map(|i| {
            let recorder = recorder.clone();
            std::thread::spawn(move || {
                for j in 0..100 {
                    recorder.lock().record(TraceEvent::TaskScheduled {
                        task_id: TaskId(i * 100 + j),
                        at_tick: j,
                    });
                }
            })
        }).collect();

        for h in handles { h.join().unwrap(); }

        let trace = Arc::try_unwrap(recorder).unwrap().into_inner().finish();
        assert_eq!(trace.events().len(), 1000);
    }

