#[test]
#[ignore]
fn stress_test_semaphore_fairness() {
    // 50 tasks acquire sequentially
    // Each records its arrival order and acquire order
    // Verify: acquire order matches arrival order (FIFO)

    let sem = Arc::new(Semaphore::new(1));
    let arrival_order = Arc::new(Mutex::new(Vec::new()));
    let acquire_order = Arc::new(Mutex::new(Vec::new()));

    for i in 0..50 {
        let s = sem.clone();
        let arr = arrival_order.clone();
        let acq = acquire_order.clone();

        spawn(async move {
            arr.lock().push(i);  // Record arrival
            let _permit = s.acquire(1).await;
            acq.lock().push(i);  // Record acquire
            // Hold permit briefly
            yield_now().await;
        });

        // Stagger arrivals to ensure ordering
        sleep(Duration::from_micros(100)).await;
    }

    // Wait for all to complete
    while acquire_order.lock().len() < 50 {
        yield_now().await;
    }

    let arr = arrival_order.lock();
    let acq = acquire_order.lock();
    assert_eq!(*arr, *acq, "Acquire order must match arrival order");
}

#[test]
#[ignore]
fn stress_test_semaphore_no_starvation() {
    // Task A requests 10 permits, many B's request 1 each
    // Verify A eventually acquires (no starvation)

    let sem = Arc::new(Semaphore::new(10));
    let a_acquired = Arc::new(AtomicBool::new(false));
    let b_count = Arc::new(AtomicU32::new(0));

    // Task A: request 10 permits
    let s1 = sem.clone();
    let a1 = a_acquired.clone();
    spawn(async move {
        let _permit = s1.acquire(10).await;
        a1.store(true, Ordering::Release);
    });

    // Many B's: request 1 permit each, release quickly
    for _ in 0..1000 {
        let s2 = sem.clone();
        let b2 = b_count.clone();
        spawn(async move {
            let _permit = s2.acquire(1).await;
            b2.fetch_add(1, Ordering::Relaxed);
            // Release immediately
        });
    }

    // Wait with timeout
    let deadline = Instant::now() + Duration::from_secs(10);
    while !a_acquired.load(Ordering::Acquire) {
        if Instant::now() > deadline {
            panic!("Task A starved! B's acquired: {}", b_count.load(Ordering::Relaxed));
        }
        yield_now().await;
    }
}
